import React from 'react';
import { KeyboardAvoidingView, Platform, StyleSheet } from 'react-native';

import { IWrapperKeyboardAvoidingViewProps } from './Models';

const styles = StyleSheet.create({
  container: { flex: 1 },
});

const WrapperKeyboardAvoidingView: React.FC<
  IWrapperKeyboardAvoidingViewProps
> = ({ children }) => {
  return (
    <KeyboardAvoidingView
      style={styles.container}
      behavior={Platform.select({
        ios: 'padding',
        android: 'height',
      })}
    >
      {children}
    </KeyboardAvoidingView>
  );
};

export { WrapperKeyboardAvoidingView };

import { Box, Image } from '@semparar/design-system-app';
import { Text } from '@semparar/design-system-app/fintech';
import React from 'react';
import { Animated } from 'react-native';
import arrow from '../../../assets/images/arrow.png';
import { AnimationArrowsViewProps } from './Models';
import { Container } from './styles';

const AnimationArrowsView = ({
  arrow1Move,
  arrow1Fade,
  arrow2Move,
  arrow2Fade,
  arrow3Move,
  arrow3Fade,
}: AnimationArrowsViewProps) => {
  return (
    <Container testID="AnimationArrowsView">
      <Box
        justify="center"
        align="center"
        width="100%"
        overflow="hidden"
        height={175}
      >
        <Box direction justify="center">
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [
                  { translateX: -35 },
                  { translateY: arrow1Move },
                ],
                opacity: arrow1Fade,
              },
            ]}
          >
            <Image
              height={41}
              width={30}
              /* @ts-ignore `source` is not in the props Of `image` ( ͡° ͜ʖ ͡°) */
              source={arrow}
            />
          </Animated.View>
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [{ translateY: arrow2Move }],
                opacity: arrow2Fade,
              },
            ]}
          >
            <Image
              height={41}
              width={30}
              /* @ts-ignore `source` is not in the props Of `image` ( ͡° ͜ʖ ͡°) */
              source={arrow}
            />
          </Animated.View>
          <Animated.View
            style={[
              {
                position: 'absolute',
                transform: [
                  { translateX: 30 },
                  { translateY: arrow3Move },
                ],
                opacity: arrow3Fade,
              },
            ]}
          >
            <Image
              height={41}
              width={30}
              /* @ts-ignore `source` is not in the props Of `image` ( ͡° ͜ʖ ͡°) */
              source={arrow}
            />
          </Animated.View>
        </Box>
      </Box>
      <Text align="center" mt="middle" type="subtitleLarger">
        Estamos carregando suas informações...
      </Text>
    </Container>
  );
};

export default AnimationArrowsView;
